// This strategy uses a more complex approach to handle the task with both
// plain text and a constrained part. It first generates unconstrained
// tokens until the parser determines it's time to enter the constrained
// region. Once inside the constrained region, it switches to constrained
// generation until it reaches the delimiter. The strategy ensures that the
// generated prefix remains valid throughout the process by using
// RollbackToValidPrefix when necessary.
// CSD_RATIONALE_END

generated := [];

while stepsLeft > 0 && !parser.IsCompletePrefix(generated)
    invariant lm.ValidTokensIdsLogits()
    invariant 0 <= stepsLeft <= maxSteps
    invariant |generated| + stepsLeft == maxSteps
    invariant helpers.InsideDelimitedWindow(generated) ==> helpers.ConstrainedWindowValid(generated)
    decreases stepsLeft
{
    var next: Token;
    var newSteps: nat;
    var inDelimitedRegion := helpers.InsideDelimitedWindow(generated);

    if inDelimitedRegion && !parser.IsCompletePrefix(helpers.GetDelimitedContent(generated))
    {
        // Use constrained step within the delimited window
        var next, newSteps := helpers.ConstrainedStep(prompt, generated, stepsLeft);
        generated := generated + [next];
        stepsLeft := newSteps;
    }
    else if generated == [] || generated[|generated|-1] != LeftDelimiter
    {
        // Use unconstrained step outside the delimited window
        var next, newSteps := helpers.UnconstrainedStep(prompt, generated, stepsLeft);
        generated := generated + [next];
        stepsLeft := newSteps;
    }
    else
    {
        // Switch to unconstrained generation when encountering the left delim
        generated := generated + [LeftDelimiter];
        stepsLeft := stepsLeft - 1;
    }
}

